sql:
SELECT id, first_name, last_name, birthday, creation_date
FROM person
WHERE id = 933;

expected_query:
FOR p IN Person
  FILTER p.id == 933
  RETURN { id: p.id, firstName: p.firstName, lastName: p.lastName, birthday: p.birthday, creationDate: p.creationDate }

generated_query:
FOR p IN Person
  FILTER p.id == 933
  RETURN { id: p.id, first_name: p.firstName, last_name: p.lastName, birthday: p.birthday, creation_date: p.creationDate }

